import React, { useEffect, useState } from 'react';
import PlantCard from '../components/PlantCard';

const categories = [
  'All', 'Indoor', 'Outdoor', 'Medicinal', 'Evergreen',
  'Flowering', 'Ornamental', 'Bonsai', 'Plant Tools'
];

const Catalog = () => {
  const [plants, setPlants] = useState([]);
  const [selectedCategory, setSelectedCategory] = useState('All');
  const [sortOption, setSortOption] = useState('name');

  useEffect(() => {
    // Replace this with actual API call or data
    fetch('/data/plants.json')
      .then((res) => res.json())
      .then((data) => setPlants(data));
  }, []);

  const handleCategoryChange = (category) => {
    setSelectedCategory(category);
  };

  const filteredPlants = plants
    .filter((plant) => selectedCategory === 'All' || plant.category === selectedCategory)
    .sort((a, b) => {
      if (sortOption === 'name') return a.name.localeCompare(b.name);
      if (sortOption === 'price') return a.price - b.price;
      return 0;
    });

  return (
    <div className="bg-white">
      {/* Header with Breadcrumb */}
      <div className="catalog-header">
        <h2 className="catalog-title">Our Plants</h2>
        <p className="catalog-breadcrumb">Home / Shop</p>
      </div>

      {/* Filter Buttons */}
      <div className="filter-buttons">
        {categories.map((category) => (
          <button
            key={category}
            onClick={() => handleCategoryChange(category)}
            className={`filter-button ${selectedCategory === category ? 'active' : ''}`}
          >
            {category}
          </button>
        ))}
      </div>

      {/* Sort Dropdown */}
      <div className="sort-dropdown">
        <label className="mr-2 text-gray-600 text-sm">Sort:</label>
        <select
          value={sortOption}
          onChange={(e) => setSortOption(e.target.value)}
          className="border border-gray-300 rounded px-3 py-1 text-sm focus:outline-green-600"
        >
          <option value="name">By Name</option>
          <option value="price">By Price</option>
        </select>
      </div>

      {/* Grid of Plants */}
      <div className="plant-grid">
        {filteredPlants.map((plant) => (
          <div key={plant.id} className="plant-card">
            <div className="plant-image-wrapper">
              <img src={plant.image} alt={plant.name} className="plant-image" />
              <div className="plant-overlay">
                <span>{plant.name}</span>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default Catalog;
